let s1 = String::from("Rust");
let s2 = s1;
// println!("{}", s1); // This would error
println!("{}", s2);

let some_number = Some(5);
match some_number {
    Some(i) => println!("{}", i),
    None => println!("Nothing"),
}

fn add(a: i32, b: i32) -> i32 {
    a + b
}
println!("{}", add(10, 20));

let mut count = 0;
for i in 0..3 {
    count += i;
}
println!("{}", count);

struct User { name: String, age: u32 }
let u = User { name: String::from("Bob"), age: 30 };
println!("{}", u.age);

let some_val: Option<i32> = None;
if let Some(v) = some_val {
    println!("{}", v);
} else {
    println!("None");
}
